func newIPFilterMiddleware(p *deps.RequestProvider) httproute.Middleware {
	request := p.Request
	appProvider := p.AppProvider
	rootProvider := appProvider.RootProvider
	environmentConfig := rootProvider.EnvironmentConfig
	trustProxy := environmentConfig.TrustProxy
	remoteIP := deps.ProvideRemoteIP(request, trustProxy)
	appContext := appProvider.AppContext
	config := appContext.Config
	appConfig := config.AppConfig
	networkProtectionConfig := appConfig.NetworkProtection
	ipFilterMiddleware := &networkprotection.IPFilterMiddleware{
		RemoteIP: remoteIP,
		Config:   networkProtectionConfig,
	}
	return ipFilterMiddleware
}
